import type { Metadata } from "next";
import EditorialWorkflow from "./EditorialWorkflow";

export const metadata: Metadata = {
  title: "編集ワークフロー / 記事管理 | ぐんじょう編集部",
  description:
    "オンラインメディア編集部の記事管理画面。記事一覧／編集ボードで タイトル・担当ライター・カテゴリ・ステータス（執筆中 / 編集中 / 校正中 / 承認待ち / 公開予定 / 公開済 / 差戻し）・公開予定日・締切(SLA) を一覧し、選択した記事を 執筆 → 編集 → 校正 → 編集長承認 → 公開 のワークフローで進行（次へ進める / 差戻し / 却下）。誤字脱字・ファクトチェック・画像権利・SEO・内部リンク・公開日時の校正チェックリストで公開をゲートし、編集長の署名による公開承認（公開後ロック）と公開スケジュールを備えた編集ワークフローツールです。",
};

export default function EditorialWorkflowPage() {
  return <EditorialWorkflow />;
}

"use client";

import * as React from "react";
import {
  Badge,
  Card,
  CardContent,
  CardHeader,
  CardTitle,
  Avatar,
  AvatarFallback,
} from "@gunjo/ui";
import {
  IconPencil,
  IconEdit,
  IconAbc,
  IconClockHour4,
  IconCalendarEvent,
  IconWorld,
  IconArrowBackUp,
  IconAlertTriangle,
} from "@tabler/icons-react";
import {
  BOARD_COLUMNS,
  STATUS_META,
  formatJpDate,
  type Article,
  type ArticleStatus,
} from "./data";

const STATUS_ICON: Record<ArticleStatus, React.ReactNode> = {
  writing: <IconPencil aria-hidden />,
  editing: <IconEdit aria-hidden />,
  proofing: <IconAbc aria-hidden />,
  review: <IconClockHour4 aria-hidden />,
  scheduled: <IconCalendarEvent aria-hidden />,
  published: <IconWorld aria-hidden />,
  "sent-back": <IconArrowBackUp aria-hidden />,
};

/** Non-color-only status pill: icon + text via Badge's `icon` slot. */
export function StatusBadge({ status }: { status: ArticleStatus }) {
  const meta = STATUS_META[status];
  return (
    <Badge variant={meta.badge} icon={STATUS_ICON[status]}>
      {meta.label}
    </Badge>
  );
}

function ArticleCard({
  article,
  selected,
  onSelect,
}: {
  article: Article;
  selected: boolean;
  onSelect: (id: string) => void;
}) {
  return (
    <Card
      role="button"
      tabIndex={0}
      aria-pressed={selected}
      aria-label={`記事「${article.title}」を開く`}
      onClick={() => onSelect(article.id)}
      onKeyDown={(e) => {
        if (e.key === "Enter" || e.key === " ") {
          e.preventDefault();
          onSelect(article.id);
        }
      }}
      className={`cursor-pointer transition-colors hover:border-foreground/30 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring ${
        selected ? "border-foreground ring-1 ring-foreground" : ""
      }`}
    >
      <CardContent className="flex flex-col gap-2 p-3">
        <div className="flex items-start gap-2">
          <span aria-hidden className="text-xl leading-none">
            {article.eyecatch}
          </span>
          <p className="min-w-0 flex-1 text-sm font-medium leading-snug text-foreground">
            {article.title}
          </p>
        </div>
        <div className="flex items-center gap-1.5 text-xs text-muted-foreground">
          <Avatar className="h-5 w-5">
            <AvatarFallback className="text-[10px]">
              {article.author.slice(0, 1)}
            </AvatarFallback>
          </Avatar>
          <span className="truncate">{article.author}</span>
          <span aria-hidden>·</span>
          <span className="truncate">{article.category}</span>
        </div>
        <div className="flex items-center justify-between gap-2">
          <span className="inline-flex items-center gap-1 text-xs text-muted-foreground">
            <IconCalendarEvent className="h-3.5 w-3.5" aria-hidden />
            {formatJpDate(article.publishAt)}
          </span>
          {article.slaAtRisk ? (
            <Badge
              variant="destructive"
              icon={<IconAlertTriangle aria-hidden />}
            >
              締切間近
            </Badge>
          ) : null}
        </div>
      </CardContent>
    </Card>
  );
}

/**
 * 編集ボード — a horizontally scrolling kanban-style board.
 * Hand-rolled: @gunjo/ui's KanbanTemplate is a layout shell only (no column /
 * card / DnD primitives), so columns + cards are composed from Card + Badge.
 */
export function ArticleBoard({
  articles,
  selectedId,
  onSelect,
}: {
  articles: Article[];
  selectedId: string | null;
  onSelect: (id: string) => void;
}) {
  return (
    <div className="overflow-x-auto pb-2">
      <ul className="flex min-w-max gap-4" aria-label="編集ボード">
        {BOARD_COLUMNS.map((col) => {
          const items = articles.filter((a) => a.status === col.status);
          return (
            <li key={col.status} className="w-64 shrink-0">
              <Card className="h-full bg-muted/30">
                <CardHeader className="flex-row items-center justify-between space-y-0 px-3 py-2.5">
                  <CardTitle as="h3" className="flex items-center gap-1.5 text-sm">
                    <span aria-hidden>{STATUS_ICON[col.status]}</span>
                    {col.label}
                  </CardTitle>
                  <Badge variant="outline" aria-label={`${items.length}件`}>
                    {items.length}
                  </Badge>
                </CardHeader>
                <CardContent className="flex flex-col gap-2 px-2 pb-2">
                  {items.length === 0 ? (
                    <p className="px-1 py-4 text-center text-xs text-muted-foreground">
                      記事なし
                    </p>
                  ) : (
                    items.map((a) => (
                      <ArticleCard
                        key={a.id}
                        article={a}
                        selected={a.id === selectedId}
                        onSelect={onSelect}
                      />
                    ))
                  )}
                </CardContent>
              </Card>
            </li>
          );
        })}
      </ul>
    </div>
  );
}

// Local domain types + seed data for the 編集ワークフロー / 記事管理 screen.
// (Editorial CMS — not part of @gunjo/ui; this is page-specific glue.)

import type { WorkflowValue } from "@gunjo/ui";

/**
 * The editorial pipeline stages, in order. The final stage is 編集長承認 —
 * reaching ApprovalWorkflow's "finish" (status: approved) unlocks the separate
 * 公開承認 (SignedRecord) action, which performs the auditable, locked publish.
 * (公開 is intentionally NOT a workflow stage; it is the signed action.)
 */
export const PIPELINE_STAGES = [
  { id: "writing", label: "執筆", name: "執筆" },
  { id: "editing", label: "編集", name: "編集" },
  { id: "proofing", label: "校正", name: "校正" },
  { id: "approval", label: "編集長承認", name: "編集長承認" },
] as const;

/**
 * Article status. Deliberately richer than the pipeline stages: it folds in the
 * out-of-band states a real editorial board needs (差戻し / 公開予定 / 公開済).
 */
export type ArticleStatus =
  | "writing" // 執筆中
  | "editing" // 編集中
  | "proofing" // 校正中
  | "review" // 承認待ち
  | "scheduled" // 公開予定
  | "published" // 公開済
  | "sent-back"; // 差戻し

export interface ProofItem {
  id: string;
  label: string;
  description?: string;
  checked: boolean;
}

export interface Article {
  id: string;
  title: string;
  slug: string;
  metaDescription: string;
  author: string; // 担当ライター
  editor: string; // 担当編集
  category: string;
  tags: string[];
  status: ArticleStatus;
  publishAt: string; // ISO date (公開予定日 / 公開日)
  /** True when the deadline (締切) is at risk relative to publishAt. */
  slaAtRisk: boolean;
  eyecatch: string; // emoji stand-in for アイキャッチ
  /** Drives the ApprovalWorkflow pipeline. */
  workflow: WorkflowValue;
  /** 校正チェックリスト state. */
  proof: ProofItem[];
  /** Locked once the editor-in-chief signs off to publish. */
  publishSigned: boolean;
  publishSignedBy?: string;
  publishSignedAt?: string;
}

export const CATEGORIES = [
  "テクノロジー",
