  { id: "seo", label: "SEO（title / description / slug）", description: "メタ情報の文字数と重複を確認", checked: overrides.seo ?? false },
  { id: "links", label: "内部リンク", description: "関連記事への導線とリンク切れ確認", checked: overrides.links ?? false },
