/** Map the ApprovalWorkflow stage/status back onto the board ArticleStatus. */
function deriveStatus(wf: WorkflowValue, signed: boolean): ArticleStatus {
  if (wf.status === "rejected") return "sent-back";
  // Pipeline complete (編集長承認 finished). Published once the editor-in-chief
  // signs the publish; until then it sits in 公開予定.
  if (wf.status === "approved") return signed ? "published" : "scheduled";
  switch (wf.currentStageId) {
    case "writing":
      return "writing";
    case "editing":
      return "editing";
    case "proofing":
      return "proofing";
    case "approval":
      return "review";
    default:
      return "writing";
  }
}

export default function EditorialWorkflow() {
  const [articles, setArticles] = React.useState<Article[]>(SEED_ARTICLES);
  const [selectedId, setSelectedId] = React.useState<string | null>(null);
  const [view, setView] = React.useState<"board" | "list">("board");
  const [query, setQuery] = React.useState("");
  const [statusFilter, setStatusFilter] = React.useState<ArticleStatus | "all">("all");

  const selected = articles.find((a) => a.id === selectedId) ?? null;

  const filtered = React.useMemo(() => {
    const q = query.trim().toLowerCase();
    return articles.filter((a) => {
      const matchesQuery =
        !q ||
        a.title.toLowerCase().includes(q) ||
        a.author.toLowerCase().includes(q) ||
        a.slug.toLowerCase().includes(q);
      const matchesStatus = statusFilter === "all" || a.status === statusFilter;
      return matchesQuery && matchesStatus;
    });
  }, [articles, query, statusFilter]);

  const stats = React.useMemo(() => {
    const total = articles.length;
    const inProgress = articles.filter((a) =>
      ["writing", "editing", "proofing", "review", "sent-back"].includes(a.status)
    ).length;
    const slaRisk = articles.filter((a) => a.slaAtRisk).length;
    const scheduled = articles.filter((a) => a.status === "scheduled").length;
    return { total, inProgress, slaRisk, scheduled };
  }, [articles]);

  const schedule = React.useMemo(
    () =>
      articles
        .filter((a) => a.status === "scheduled" || a.status === "published")
        .slice()
        .sort((a, b) => a.publishAt.localeCompare(b.publishAt)),
    [articles]
  );

  const patchArticle = (id: string, patch: Partial<Article>) =>
    setArticles((prev) => prev.map((a) => (a.id === id ? { ...a, ...patch } : a)));

  // ----- Pipeline (ApprovalWorkflow) wiring -----
  const proofComplete = (proof: ProofItem[]) => proof.every((p) => p.checked);

  const handleWorkflowChange = (article: Article, next: WorkflowValue) => {
    patchArticle(article.id, {
      workflow: next,
      status: deriveStatus(next, article.publishSigned),
    });
  };

  const handleProofToggle = (article: Article, id: string, checked: boolean) => {
    const proof = article.proof.map((p) => (p.id === id ? { ...p, checked } : p));
    // Proof state only re-derives status while still in the 校正 stage (a freshly
    // unticked item should not change a later stage's board column).
    patchArticle(article.id, { proof });
  };

  const handleSign = (article: Article) =>
    patchArticle(article.id, {
      publishSigned: true,
      publishSignedBy: CURRENT_USER,
      publishSignedAt: new Date().toISOString(),
      status: "published",
    });

  // The proofing checklist gates advancing OUT of 校正 and the final publish.
  const proofDone = selected ? proofComplete(selected.proof) : false;
  const atProofingStage = selected?.workflow.currentStageId === "proofing";
  const canAdvance = !atProofingStage || proofDone;

  // ----- DataTable columns (list view) -----
  const columns: ColumnDef<Article>[] = [
    {
      accessorKey: "title",
      header: "タイトル",
