  return (
    <main className="mx-auto w-full max-w-7xl px-4 py-6 sm:px-6 lg:px-8">
      <header className="mb-6 flex flex-col gap-1">
        <p className="text-sm text-muted-foreground">ぐんじょう編集部</p>
        <h1 className="text-2xl font-bold tracking-tight">編集ワークフロー / 記事管理</h1>
        <p className="text-sm text-muted-foreground">
          記事を 執筆 → 編集 → 校正 → 編集長承認 → 公開 の流れで進行し、校正チェックリストで公開をゲートします。
        </p>
      </header>

      {/* KPI strip */}
      <section aria-label="編集部の概況" className="mb-6 grid grid-cols-2 gap-3 lg:grid-cols-4">
        <Card>
          <CardContent className="p-4">
            <Statistic label="記事総数" value={stats.total} hint="今月の管理対象" />
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4">
            <Statistic label="進行中" value={stats.inProgress} hint="公開前の記事" />
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4">
            <Statistic
              label="締切間近"
              value={stats.slaRisk}
              change={stats.slaRisk > 0 ? "要対応" : undefined}
              tone={stats.slaRisk > 0 ? "negative" : "neutral"}
              hint="SLA注意"
            />
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4">
            <Statistic label="公開予定" value={stats.scheduled} hint="承認済み" />
          </CardContent>
        </Card>
      </section>

      <div className="grid grid-cols-1 gap-6 lg:grid-cols-[1fr_320px]">
        {/* Main column: board / list */}
        <section aria-label="記事一覧" className="min-w-0">
          {/* Controls */}
          <div className="mb-4 flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
