          ) : view === "board" ? (
            <ArticleBoard articles={filtered} selectedId={selectedId} onSelect={setSelectedId} />
          ) : (
            <DataTable
              columns={columns}
              data={filtered}
              filter={null}
              pageSize={10}
              labels={{
                noResults: "該当する記事がありません",
                previous: "前へ",
                next: "次へ",
                firstPage: "最初のページ",
                lastPage: "最後のページ",
                rowsPerPage: "表示件数",
                sortAscending: "昇順で並び替え",
                sortDescending: "降順で並び替え",
                clearSort: "並び替えを解除",
