              <CardDescription>承認済み・公開済みの記事を公開日順に表示</CardDescription>
            </CardHeader>
            <CardContent>
              {schedule.length === 0 ? (
                <p className="text-sm text-muted-foreground">予定はありません。</p>
              ) : (
