                <SheetDescription className="flex flex-wrap items-center gap-2 text-left">
                  <StatusBadge status={selected.status} />
                  <span>担当: {selected.author}</span>
                  <span aria-hidden>·</span>
                  <span>編集: {selected.editor}</span>
                </SheetDescription>
              </SheetHeader>

              <Tabs defaultValue="pipeline" className="mt-4 border-0">
                <TabsList className="w-full justify-start overflow-x-auto">
                  <TabsTrigger value="pipeline">ワークフロー</TabsTrigger>
                  <TabsTrigger value="proof">校正チェック</TabsTrigger>
                  <TabsTrigger value="seo">メタ / SEO</TabsTrigger>
                  <TabsTrigger value="publish">公開承認</TabsTrigger>
                </TabsList>

                {/* Pipeline */}
                <TabsContent value="pipeline" className="px-0">
                  <h3 className="mb-3 text-sm font-semibold">編集ワークフロー</h3>
                  <ApprovalWorkflow
                    stages={[...PIPELINE_STAGES]}
                    value={selected.workflow}
                    onChange={(next) => handleWorkflowChange(selected, next)}
                    actor={CURRENT_USER}
                    canAdvance={canAdvance}
                    advanceHint={
                      !canAdvance ? "校正チェックリストが未完了です" : undefined
                    }
                    labels={{
                      advance: "次の段階へ進める",
                      finish: "公開可能にする",
                      sendBack: "差戻し（ライターへ）",
                      reject: "却下",
                      sendBackTarget: "戻し先の段階",
                      reason: "差戻し理由",
                      reasonPlaceholder: "修正してほしい点を具体的に…",
                      completed: "全工程を完了しました。公開承認タブで公開できます。",
                      rejected: "この記事は却下されました。",
                    }}
                    stateLabels={{
                      pending: "未着手",
                      current: "進行中",
                      approved: "完了",
                      rejected: "差戻し / 却下",
                      skipped: "スキップ",
                    }}
                  />
                </TabsContent>

                {/* Proofing checklist */}
                <TabsContent value="proof" className="px-0">
                  <div className="mb-3 flex items-center justify-between">
                    <h3 className="text-sm font-semibold">校正チェックリスト（公開ゲート）</h3>
                    {proofDone ? (
                      <Badge variant="success" icon={<IconCircleCheck aria-hidden />}>
                        完了
                      </Badge>
                    ) : (
                      <Badge variant="warning" icon={<IconClockExclamation aria-hidden />}>
                        {selected.proof.filter((p) => p.checked).length}/{selected.proof.length}
                      </Badge>
                    )}
                  </div>
                  <CheckList
                    items={selected.proof.map((p) => ({
                      id: p.id,
                      label: p.label,
                      description: p.description,
                      checked: p.checked,
                      trailing: p.checked ? (
                        <Badge variant="success">確認済</Badge>
                      ) : (
                        <Badge variant="outline">未確認</Badge>
                      ),
                    }))}
                    onCheckedChange={(id, checked) => handleProofToggle(selected, id, checked)}
                  />
                  {!proofDone ? (
                    <p className="mt-3 text-xs text-muted-foreground">
                      すべての項目を確認すると、校正段階を進められるようになります。
                    </p>
                  ) : null}
                </TabsContent>

                {/* SEO / meta */}
                <TabsContent value="seo" className="px-0">
                  <h3 className="mb-3 text-sm font-semibold">記事メタ / SEO</h3>
                  <SeoMetaEditor
                    article={selected}
                    readOnly={selected.publishSigned}
                    onChange={(patch) => patchArticle(selected.id, patch)}
                  />
                </TabsContent>

                {/* Publish approval */}
                <TabsContent value="publish" className="px-0">
                  <h3 className="mb-3 text-sm font-semibold">公開承認</h3>
                  <PublishApproval
                    article={selected}
                    signerId={CURRENT_USER}
                    canPublish={
                      selected.workflow.status === "approved" && proofDone && !selected.publishSigned
                    }
                    blockingReason={
                      selected.workflow.status !== "approved"
                        ? "ワークフローが「公開可能」になっていません。"
                        : !proofDone
                        ? "校正チェックリストが未完了です。"
                        : undefined
                    }
                    onSign={() => handleSign(selected)}
                  />
                </TabsContent>
              </Tabs>
            </>
          ) : null}
        </SheetContent>
      </Sheet>
    </main>
  );
}

"use client";

import * as React from "react";
import { SignedRecord, MetadataList, Badge } from "@gunjo/ui";
import { IconCalendarEvent, IconUser, IconLink, IconCategory } from "@tabler/icons-react";
import { formatJpDate, type Article } from "./data";

/**
 * 公開承認 — an auditable approve-to-publish action that locks after publish.
 * Built on SignedRecord (designed for clinical/legal signed records): once the
 * editor-in-chief signs, the publish snapshot is locked read-only and only
 * append-only addenda (e.g. 公開後の訂正メモ) are allowed. Cross-domain reuse.
 */
export function PublishApproval({
  article,
  signerId,
  canPublish,
  blockingReason,
  onSign,
}: {
  article: Article;
  signerId: string;
  canPublish: boolean;
  blockingReason?: React.ReactNode;
  onSign: () => void;
}) {
  return (
    <div className="flex flex-col gap-3">
      {!canPublish && !article.publishSigned ? (
        <p
          role="status"
          className="rounded-md border border-warning-border bg-warning-subtle px-3 py-2 text-sm text-warning-subtle-foreground"
        >
          {blockingReason ?? "公開の条件が満たされていません。"}
        </p>
      ) : null}

      <SignedRecord
        value={{
          status: article.publishSigned ? "signed" : "draft",
          signedBy: article.publishSignedBy,
          signedAt: article.publishSignedAt,
          addenda: [],
        }}
        signerId={signerId}
        canSign={canPublish}
        requireAddendumReason
        onChange={(next) => {
          if (next.status === "signed" && !article.publishSigned) onSign();
        }}
        labels={{
          draft: "公開前（未承認）",
          signed: "公開承認済・ロック",
          sign: "編集長として公開を承認",
          locked: "公開承認済みの記事です。内容の変更は訂正メモ（追記）で行います。",
          signedByLabel: "承認",
          addendaTitle: "公開後の訂正メモ",
          addendum: "訂正メモを追記",
          addendumBody: "訂正内容",
          addendumReason: "理由",
          addendumSubmit: "追記する",
        }}
      >
        {() => (
          <div className="rounded-md border bg-card p-3">
            <div className="mb-2 flex items-center gap-2">
              <span aria-hidden className="text-2xl">
                {article.eyecatch}
              </span>
              <p className="text-sm font-medium leading-snug">{article.title}</p>
            </div>
            <MetadataList
              variant="compact"
              items={[
                { label: "担当ライター", value: article.author, icon: <IconUser className="h-3.5 w-3.5" /> },
                { label: "カテゴリ", value: article.category, icon: <IconCategory className="h-3.5 w-3.5" /> },
                {
                  label: "公開予定",
                  value: formatJpDate(article.publishAt),
                  icon: <IconCalendarEvent className="h-3.5 w-3.5" />,
                },
                {
                  label: "slug",
                  value: <code className="text-xs">{article.slug}</code>,
                  icon: <IconLink className="h-3.5 w-3.5" />,
                },
              ]}
            />
          </div>
        )}
      </SignedRecord>

      {article.publishSigned ? (
        <Badge variant="success" className="self-start">
          公開済み・監査ログに記録されました
        </Badge>
      ) : null}
    </div>
  );
}

"use client";

import * as React from "react";
import {
  Input,
  Textarea,
  Select,
  TagInput,
  Meter,
  Label,
} from "@gunjo/ui";
import { CATEGORIES, type Article } from "./data";

/** Recommended length windows for SEO fields (chars). */
const TITLE_MAX = 32;
const DESC_MAX = 120;

/**
 * SEO length guidance is NOT a built-in @gunjo/ui prop on Input/Textarea
 * (no maxLength readout / counter). It is composed here from `Meter`
 * (direction-aware capacity bar with a target marker) — a cross-domain reuse:
 * Meter is documented for kg/m³/SLA capacity, and bends cleanly to "chars / max".
 */
function LengthMeter({
  id,
  value,
  max,
  unit = "字",
}: {
  id: string;
  value: number;
  max: number;
  unit?: string;
}) {
  const over = value > max;
  return (
    <div className="flex items-center gap-3">
      <div className="min-w-0 flex-1">
        <Meter
          id={id}
          value={value}
          max={max}
          size="inline"
          unit={unit}
          showValue={false}
          label="文字数"
          // near the cap warns, over the cap flags — exactly the SEO intent.
          thresholds={{ warning: 0.85, over: 1 }}
          valueText={`${value}${unit} / 推奨 ${max}${unit}`}
        />
      </div>
      <span
        className={`shrink-0 text-xs tabular-nums ${
          over ? "text-destructive font-medium" : "text-muted-foreground"
        }`}
      >
        {value} / {max}
        {unit}
        {over ? "（超過）" : ""}
      </span>
    </div>
  );
}

export function SeoMetaEditor({
