          {article.eyecatch}
        </div>
        <div className="flex flex-col gap-1">
          <Label htmlFor="eyecatch">アイキャッチ（絵文字）</Label>
          <Input
            id="eyecatch"
            value={article.eyecatch}
            disabled={readOnly}
            maxLength={2}
            className="w-20"
            onChange={(e) => onChange({ eyecatch: e.target.value })}
          />
        </div>
      </div>

      {/* Title + length meter */}
      <div className="flex flex-col gap-1.5">
