      />

      {/* Meta description + length meter */}
      <div className="flex flex-col gap-1.5">
        <Textarea
          id="seo-desc"
          label="メタディスクリプション"
          value={article.metaDescription}
          disabled={readOnly}
          rows={3}
          description="検索結果のスニペットに表示されます。推奨は120字以内。"
          onChange={(e) => onChange({ metaDescription: e.target.value })}
        />
        <LengthMeter
          id="seo-desc-len"
          value={article.metaDescription.length}
          max={DESC_MAX}
        />
      </div>

      {/* Category */}
      <Select
        id="seo-category"
        label="カテゴリ"
        value={article.category}
        disabled={readOnly}
        onChange={(e) => onChange({ category: e.target.value })}
      >
        {CATEGORIES.map((c) => (
          <option key={c} value={c}>
            {c}
          </option>
        ))}
      </Select>

      {/* Tags */}
      <div className="flex flex-col gap-1.5">
        <Label htmlFor="seo-tags">タグ</Label>
        <TagInput
          id="seo-tags"
          value={article.tags}
          disabled={readOnly}
          placeholder="タグを入力して Enter"
          onValueChange={(tags) => onChange({ tags })}
        />
      </div>
    </div>
  );
}
